            Write-Output '[!!]  BitLocker Status'
            Write-Output '       BitLocker is not available on this Windows edition.'
            Write-Output "       WMI namespace not found: $wmiErr"
            $issueCount++
        } else {
            Write-Output '[!!]  BitLocker Status'
            Write-Output '       Could not query BitLocker volumes.'
