Write-Output '--- Modern Standby ---'

$modernStandbySupported = $false
$csEnabled = $null
$aoAcOverride = $null

# Check CsEnabled registry
$powerPath = 'HKLM:\SYSTEM\CurrentControlSet\Control\Power'
try {
